static int parse_request(http_request_t *req) {
    if (!req || !req->raw_buffer || req->raw_length == 0) {
        return -1;
    }

    char *buffer = strdup(req->raw_buffer);
    if (!buffer) return -1;

    char *line = strtok(buffer, "\r\n");
    if (!line) {
        free(buffer);
        return -1;
    }

    char method_str[16] = {0};
    char path[MAX_PATH_LENGTH] = {0};
    char version[16] = {0};

    if (sscanf(line, "%15s %255s %15s", method_str, path, version) != 3) {
        free(buffer);
        return -1;
    }

    req->method = parse_method(method_str);
    strncpy(req->path, path, MAX_PATH_LENGTH - 1);
    strncpy(req->version, version, sizeof(req->version) - 1);

    req->header_count = 0;
    while ((line = strtok(NULL, "\r\n")) != NULL && req->header_count < MAX_HEADERS) {
        if (strlen(line) == 0) break;

        char *colon = strchr(line, ':');
        if (colon) {
            size_t name_len = colon - line;
            if (name_len < sizeof(req->headers[0].name)) {
                strncpy(req->headers[req->header_count].name, line, name_len);
                req->headers[req->header_count].name[name_len] = '\0';

                char *value = colon + 1;
                while (*value == ' ') value++;
                strncpy(req->headers[req->header_count].value, value,
                        sizeof(req->headers[0].value) - 1);

                req->header_count++;
            }
        }
    }

    free(buffer);
    return 0;
}

