static int build_response(http_response_t *resp) {
    if (!resp || !resp->response_buffer || !resp->body) return -1;

    int written = snprintf(resp->response_buffer, resp->response_length,
        "HTTP/1.1 %d %s\r\n"
        "Content-Type: %s\r\n"
        "Content-Length: %zu\r\n"
        "Connection: keep-alive\r\n"
        "Server: EmbeddedWebServer/1.0\r\n"
        "\r\n"
        "%s",
        resp->status_code,
        resp->status_text,
        resp->content_type,
        resp->body_length,
        resp->body);

    if (written < 0 || (size_t)written >= resp->response_length) {
        return -1;
    }

    return written;
}

static int process_request(http_request_t *req, http_response_t *resp) {
    if (parse_request(req) != 0) {
        resp->status_code = 400;
        strncpy(resp->status_text, "Bad Request", sizeof(resp->status_text) - 1);
        strncpy(resp->content_type, "text/html", sizeof(resp->content_type) - 1);

        const char *bad_req_body = "<html><body><h1>400 Bad Request</h1></body></html>";
        resp->body_length = strlen(bad_req_body);
        resp->body = (char *)malloc(resp->body_length + 1);
        if (!resp->body) return -1;
        strcpy(resp->body, bad_req_body);

        return build_response(resp);
    }

    int result = -1;
    switch (req->method) {
        case HTTP_GET:
            result = handle_get(req, resp);
            break;
        case HTTP_POST:
            result = handle_post(req, resp);
            break;
        case HTTP_PUT:
            result = handle_put(req, resp);
            break;
        case HTTP_DELETE:
            result = handle_delete(req, resp);
            break;
        default:
            resp->status_code = 405;
            strncpy(resp->status_text, "Method Not Allowed", sizeof(resp->status_text) - 1);
            strncpy(resp->content_type, "text/html", sizeof(resp->content_type) - 1);
            const char *na_body = "<html><body><h1>405 Method Not Allowed</h1></body></html>";
            resp->body_length = strlen(na_body);
            resp->body = (char *)malloc(resp->body_length + 1);
            if (!resp->body) return -1;
            strcpy(resp->body, na_body);
            result = 0;
            break;
    }

    if (result != 0) return -1;

    return build_response(resp);
}

static void simulate_incoming_request(http_request_t *req, int request_num) {
    const char *requests[] = {
        "GET / HTTP/1.1\r\nHost: localhost\r\nUser-Agent: TestClient/1.0\r\nAccept: text/html\r\n\r\n",
        "GET /status HTTP/1.1\r\nHost: localhost\r\nUser-Agent: TestClient/1.0\r\nAccept: application/json\r\n\r\n",
        "GET /api/data HTTP/1.1\r\nHost: localhost\r\nUser-Agent: TestClient/1.0\r\nAccept: application/json\r\n\r\n",
        "POST /api/data HTTP/1.1\r\nHost: localhost\r\nContent-Type: application/json\r\nContent-Length: 27\r\n\r\n{\"key\":\"value\",\"num\":42}",
        "PUT /api/data/1 HTTP/1.1\r\nHost: localhost\r\nContent-Type: application/json\r\nContent-Length: 31\r\n\r\n{\"key\":\"updated\",\"num\":100}",
        "DELETE /api/data/1 HTTP/1.1\r\nHost: localhost\r\nAccept: application/json\r\n\r\n",
        "GET /nonexistent HTTP/1.1\r\nHost: localhost\r\nAccept: text/html\r\n\r\n",
        "PATCH /api/data HTTP/1.1\r\nHost: localhost\r\n\r\n",
    };

    int num_requests = sizeof(requests) / sizeof(requests[0]);
    int idx = request_num % num_requests;

    strncpy(req->raw_buffer, requests[idx], MAX_REQUEST_SIZE - 1);
    req->raw_buffer[MAX_REQUEST_SIZE - 1] = '\0';
    req->raw_length = strlen(req->raw_buffer);
}

static double get_time_ms(void) {
    struct timespec ts;
    clock_gettime(CLOCK_MONOTONIC, &ts);
    return ts.tv_sec * 1000.0 + ts.tv_nsec / 1000000.0;
}

int main(void) {
    server_stats_t stats = {0};
    bool running = true;
    int request_counter = 0;

    srand((unsigned int)time(NULL));

    printf("========================================\n");
    printf("  Embedded Web Server v1.0\n");
    printf("  Processing %d simulated requests\n", SIMULATED_REQUESTS);
    printf("========================================\n\n");

    double server_start = get_time_ms();

    while (running) {
        double req_start = get_time_ms();

        http_request_t *request = alloc_request();
        if (!request) {
            fprintf(stderr, "Error: Failed to allocate request #%d\n", request_counter);
            stats.failed_requests++;
            stats.total_requests++;
            continue;
        }

        http_response_t *response = alloc_response();
        if (!response) {
            fprintf(stderr, "Error: Failed to allocate response #%d\n", request_counter);
            free_request(request);
            stats.failed_requests++;
            stats.total_requests++;
            continue;
        }

        simulate_incoming_request(request, request_counter);
        stats.bytes_received += request->raw_length;

        int response_len = process_request(request, response);

        double req_end = get_time_ms();
        double elapsed = req_end - req_start;
        stats.total_processing_time_ms += elapsed;

        if (response_len > 0) {
            stats.successful_requests++;
            stats.bytes_sent += response_len;

            printf("[Request #%03d] %s %s -> %d %s (%.3f ms)\n",
                   request_counter,
                   method_to_string(request->method),
                   request->path,
                   response->status_code,
                   response->status_text,
                   elapsed);
        } else {
            stats.failed_requests++;
            printf("[Request #%03d] FAILED - Could not process request (%.3f ms)\n",
                   request_counter, elapsed);
        }

        stats.total_requests++;

        free_response(response);
        free_request(request);

        request_counter++;
        if (request_counter >= SIMULATED_REQUESTS) {
            running = false;
        }
    }

    double server_end = get_time_ms();
    double total_time = server_end - server_start;

    printf("\n========================================\n");
    printf("  Server Statistics\n");
    printf("========================================\n");
    printf("  Total requests:      %lu\n", stats.total_requests);
    printf("  Successful:          %lu\n", stats.successful_requests);
    printf("  Failed:              %lu\n", stats.failed_requests);
    printf("  Bytes received:      %lu\n", stats.bytes_received);
    printf("  Bytes sent:          %lu\n", stats.bytes_sent);
    printf("  Total time:          %.3f ms\n", total_time);
    printf("  Avg time/request:    %.3f ms\n",
           stats.total_requests > 0 ? stats.total_processing_time_ms / stats.total_requests : 0);
    printf("  Throughput:          %.1f req/sec\n",
           total_time > 0 ? (stats.total_requests * 1000.0) / total_time : 0);
    printf("========================================\n");

    return 0;
}